---@class LTreasureBubble:LBubbleBase
local LTreasureBubble = LxClass("LTreasureBubble", LBubbleBase)
local typeOfTextMesh = typeof(CS.TextMeshPro)
local typeSpriteRenderer = typeof(UnityEngine.SpriteRenderer)
local BuildingClick = CS.BuildingClick
local Tweening = DG.Tweening


function LTreasureBubble:LTreasureBubble()
    self._seqCom = SequenceCom:New()
end

function LTreasureBubble:GetPrefabPath()
    return "UI/Prefabs/Com/TreasureBubble","UI/Prefabs/Com","TreasureBubble"
end

function LTreasureBubble:OnSetBubbleContent(item,itemdata)
    local bubble = CS.FindTrans(item,"bubble")
    local text = CS.FindTrans(item,"bubble/UIText")
    local collider = CS.FindTrans(item,"bubble/GameObject")
    local tag = CS.FindTrans(item,"bubble/tag")
    --self:SetXTextContent(text,itemdata.text)
    if itemdata.noShowCollider then
        CS.ShowObject(collider,false)
    end
    if itemdata.noShowTag then
        CS.ShowObject(tag,false)
    end
    local bubbleSprite = bubble:GetComponent(typeSpriteRenderer)
    if bubbleSprite then
        bubbleSprite.sortingOrder = 1
        local sprite = itemdata.sprite
        self:SetSprite(item,bubble,sprite)
    end
    local com = text:GetComponent(typeOfTextMesh)
    if com then
        --com.text = itemdata.text
        self:SetXTextMeshProContent(text, itemdata.text)
        local renderer = com.renderer
        renderer.sortingLayerName = "Object"
        renderer.sortingOrder = 2
    end
    self:SetFollow(itemdata.followTran,itemdata.offset)
    local img = CS.FindTrans(item,"bubble")
    local comp = BuildingClick.Get(img.gameObject)
    if comp then
        comp.ClickDelegate = itemdata.callBack
    end

    local seq = self._seqCom:CreateSeq("scale")
    item.localScale = Vector3.one
    local tween = item:DOScale(Vector3.one*0.9,1)
    seq:Append(tween)
    seq:SetLoops(-1,Tweening.LoopType.Yoyo)
    seq:PlayForward()
end


return LTreasureBubble